  });

  it('throws in remote mode when DSG_CORE_URL is missing', async () => {
    process.env.DSG_CORE_MODE = 'remote';

    await expect(getDSGCoreHealth()).rejects.toThrow('DSG_CORE_URL is required when DSG_CORE_MODE=remote');
  });
